// frontend/src/pages/History.jsx — Member 5
// Transaction History + Token Balance

import { useState, useEffect } from "react";
import { getCrowdfundingContract, getRewardTokenContract, fromWei } from "../utils/contracts";
import addresses from "../utils/addresses.json";
import CrowdfundingABI from "../utils/abi/Crowdfunding.json";
import { ethers } from "ethers";
 
const TYPES = {
  "Contribution":  { color: "#7C71F2", dot: "#7C71F2", icon: "↑" },
  "Withdrawal":    { color: "#34D399", dot: "#34D399", icon: "↓" },
  "Refund":        { color: "#FBBF24", dot: "#FBBF24", icon: "↩" },
  "Tokens Minted": { color: "#F472B6", dot: "#F472B6", icon: "✦" },
};
 
export default function History({ user }) {
  const [tokenBalance, setTokenBalance] = useState("0");
  const [history, setHistory]           = useState([]);
  const [loading, setLoading]           = useState(false);
  const [error, setError]               = useState("");
  const [filter, setFilter]             = useState("All");
  const [copied, setCopied]             = useState(null);
 
  useEffect(() => { loadTokenBalance(); loadHistory(); }, []);
 
  async function loadTokenBalance() {
    try {
      const contract = await getRewardTokenContract();
      const bal = await contract.getBalance(user.address);
      setTokenBalance(ethers.formatUnits(bal, 18));
    } catch (err) { console.error(err); }
  }
 
  async function loadHistory() {
    try {
      setLoading(true);
      const provider = new ethers.BrowserProvider(window.ethereum);
      const contract = new ethers.Contract(addresses.Crowdfunding, CrowdfundingABI.abi, provider);
      const [funded, withdrawn, refunded, minted] = await Promise.all([
        contract.queryFilter(contract.filters.Funded(null, user.address)),
        contract.queryFilter(contract.filters.Withdrawn(null, user.address)),
        contract.queryFilter(contract.filters.Refunded(null, user.address)),
        contract.queryFilter(contract.filters.TokensMinted(null, user.address)),
      ]);
      const entries = [
        ...funded.map(e => ({ type: "Contribution", campaignId: e.args.campaignId.toString(), amount: fromWei(e.args.amount), unit: "ETH", txHash: e.transactionHash, block: e.blockNumber })),
        ...withdrawn.map(e => ({ type: "Withdrawal", campaignId: e.args.campaignId.toString(), amount: fromWei(e.args.amount), unit: "ETH", txHash: e.transactionHash, block: e.blockNumber })),
        ...refunded.map(e => ({ type: "Refund", campaignId: e.args.campaignId.toString(), amount: fromWei(e.args.amount), unit: "ETH", txHash: e.transactionHash, block: e.blockNumber })),
        ...minted.map(e => ({ type: "Tokens Minted", campaignId: e.args.campaignId.toString(), amount: e.args.tokens.toString(), unit: "BTK", txHash: e.transactionHash, block: e.blockNumber })),
      ];
      entries.sort((a, b) => b.block - a.block);
      setHistory(entries);
    } catch (err) { setError(err.message); }
    finally { setLoading(false); }
  }
 
  function copyHash(hash) {
    navigator.clipboard.writeText(hash);
    setCopied(hash);
    setTimeout(() => setCopied(null), 1500);
  }
 
  const FILTERS = ["All", ...Object.keys(TYPES)];
  const filtered = filter === "All" ? history : history.filter(h => h.type === filter);
  const totalETH = history.filter(h => h.unit === "ETH" && h.type === "Contribution").reduce((s, h) => s + parseFloat(h.amount), 0).toFixed(3);
 
  return (
    <div style={s.root}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&display=swap');
        @keyframes fadeIn { from{opacity:0;transform:translateY(6px)} to{opacity:1;transform:translateY(0)} }
        @keyframes spin { to{transform:rotate(360deg)} }
        .tx-row:hover { background: #1C1C1F !important; }
        .filter-pill:hover { background: #2A2A2E !important; }
        .copy-btn:hover { color: #fff !important; }
      `}</style>
 
      {/* ── Page Title ── */}
      <div style={s.topBar}>
        <div>
          <h1 style={s.title}>Activity</h1>
          <p style={s.subtitle}>{user.address?.slice(0,6)}...{user.address?.slice(-4)}</p>
        </div>
        <button onClick={() => { loadTokenBalance(); loadHistory(); }} style={s.refreshBtn}>
          <span style={{ fontSize: 13 }}>↻</span> Refresh
        </button>
      </div>
 
      {/* ── Metric Cards ── */}
      <div style={s.metricsRow}>
        <div style={s.metricCard}>
          <p style={s.metricLabel}>BTK Balance</p>
          <p style={{ ...s.metricVal, color: "#F472B6" }}>{Number(tokenBalance).toFixed(2)}<span style={s.metricUnit}> BTK</span></p>
          <div style={{ ...s.metricBar, background: "#F472B620" }}>
            <div style={{ ...s.metricBarFill, width: Math.min(Number(tokenBalance) * 10, 100) + "%", background: "#F472B6" }} />
          </div>
        </div>
 
        <div style={s.metricCard}>
          <p style={s.metricLabel}>Total Contributed</p>
          <p style={{ ...s.metricVal, color: "#7C71F2" }}>{totalETH}<span style={s.metricUnit}> ETH</span></p>
          <div style={{ ...s.metricBar, background: "#7C71F220" }}>
            <div style={{ ...s.metricBarFill, width: Math.min(parseFloat(totalETH) * 10, 100) + "%", background: "#7C71F2" }} />
          </div>
        </div>
 
        <div style={s.metricCard}>
          <p style={s.metricLabel}>Transactions</p>
          <p style={{ ...s.metricVal, color: "#34D399" }}>{history.length}<span style={s.metricUnit}> total</span></p>
          <div style={s.txTypeRow}>
            {Object.entries(TYPES).map(([type, cfg]) => {
              const count = history.filter(h => h.type === type).length;
              return count > 0 ? (
                <span key={type} style={{ display: "flex", alignItems: "center", gap: 4, fontSize: 11, color: "#666" }}>
                  <span style={{ width: 6, height: 6, borderRadius: "50%", background: cfg.dot, display: "inline-block" }} />
                  {count}
                </span>
              ) : null;
            })}
          </div>
        </div>
      </div>
 
      {/* ── Filter Pills ── */}
      <div style={s.filterRow}>
        {FILTERS.map(f => {
          const count = f === "All" ? history.length : history.filter(h => h.type === f).length;
          const active = filter === f;
          const color = f === "All" ? "#7C71F2" : TYPES[f]?.color;
          return (
            <button key={f} className="filter-pill"
              onClick={() => setFilter(f)}
              style={{ ...s.pill, ...(active ? { background: color + "20", border: "1px solid " + color + "40", color } : {}) }}>
              {f !== "All" && <span style={{ width: 6, height: 6, borderRadius: "50%", background: active ? color : "#555", display: "inline-block" }} />}
              {f}
              <span style={{ ...s.pillCount, ...(active ? { background: color + "25", color } : {}) }}>{count}</span>
            </button>
          );
        })}
      </div>
 
      {/* ── Transaction List ── */}
      <div style={s.listCard}>
 
        {/* Header row */}
        <div style={s.listHeader}>
          <span style={{ flex: 2 }}>TYPE</span>
          <span style={{ flex: 1.5 }}>CAMPAIGN</span>
          <span style={{ flex: 1 }}>AMOUNT</span>
          <span style={{ flex: 1 }}>BLOCK</span>
          <span style={{ flex: 2 }}>TX HASH</span>
        </div>
 
        {/* Loading */}
        {loading && (
          <div style={s.centerState}>
            <div style={s.spinner} />
            <p style={{ color: "#555", fontSize: 13, marginTop: 14 }}>Fetching transactions...</p>
          </div>
        )}
 
        {/* Error */}
        {error && !loading && (
          <div style={s.centerState}>
            <p style={{ color: "#F87171", fontSize: 13 }}>⚠ {error}</p>
          </div>
        )}
 
        {/* Empty */}
        {!loading && !error && filtered.length === 0 && (
          <div style={s.centerState}>
            <div style={s.emptyIcon}>◈</div>
            <p style={{ color: "#555", fontSize: 14, margin: "10px 0 4px", fontWeight: 500 }}>No transactions found</p>
            <p style={{ color: "#3A3A3D", fontSize: 12 }}>Activity will appear here once you interact with campaigns</p>
          </div>
        )}
 
        {/* Rows */}
        {!loading && filtered.map((row, i) => {
          const cfg = TYPES[row.type];
          return (
            <div key={i} className="tx-row"
              style={{ ...s.listRow, animationDelay: i * 0.04 + "s" }}>
 
              {/* Type */}
              <div style={{ flex: 2, display: "flex", alignItems: "center", gap: 10 }}>
                <div style={{ ...s.iconBox, background: cfg.color + "15", color: cfg.color }}>
                  {cfg.icon}
                </div>
                <span style={{ fontSize: 13, color: "#D1D1D6", fontWeight: 500 }}>{row.type}</span>
              </div>
 
              {/* Campaign */}
              <div style={{ flex: 1.5 }}>
                <span style={s.campaignTag}>Campaign #{row.campaignId}</span>
              </div>
 
              {/* Amount */}
              <div style={{ flex: 1 }}>
                <span style={{ fontSize: 14, fontWeight: 600, color: cfg.color }}>
                  {row.amount}
                </span>
                <span style={{ fontSize: 12, color: "#555", marginLeft: 4 }}>{row.unit}</span>
              </div>
 
              {/* Block */}
              <div style={{ flex: 1 }}>
                <span style={s.blockTag}>#{row.block}</span>
              </div>
 
              {/* Tx Hash */}
              <div style={{ flex: 2, display: "flex", alignItems: "center", gap: 6 }}>
                <span style={s.hashText}>
                  {row.txHash.slice(0, 10)}...{row.txHash.slice(-6)}
                </span>
                <button className="copy-btn"
                  onClick={() => copyHash(row.txHash)}
                  style={{ ...s.copyBtn, color: copied === row.txHash ? "#34D399" : "#444" }}>
                  {copied === row.txHash ? "✓" : "⎘"}
                </button>
              </div>
            </div>
          );
        })}
 
        {/* Footer */}
        {!loading && filtered.length > 0 && (
          <div style={s.listFooter}>
            Showing {filtered.length} of {history.length} transactions
          </div>
        )}
      </div>
    </div>
  );
}
 
const s = {
  root: {
    maxWidth: 920, margin: "0 auto", padding: "32px 24px",
    fontFamily: "'Inter', -apple-system, sans-serif",
    minHeight: "100vh",
  },
  topBar: {
    display: "flex", justifyContent: "space-between",
    alignItems: "flex-start", marginBottom: 32,
  },
  title: {
    margin: 0, fontSize: 28, fontWeight: 600,
    color: "#F5F5F7", letterSpacing: "-0.6px",
  },
  subtitle: {
    margin: "4px 0 0", fontSize: 12, color: "#48484A",
    fontFamily: "monospace",
  },
  refreshBtn: {
    display: "flex", alignItems: "center", gap: 6,
    padding: "7px 14px", background: "#1C1C1F",
    border: "1px solid #2C2C2E", borderRadius: 8,
    color: "#8E8E93", fontSize: 12, fontWeight: 500,
    cursor: "pointer", fontFamily: "inherit",
  },
  metricsRow: {
    display: "grid", gridTemplateColumns: "repeat(3,1fr)",
    gap: 12, marginBottom: 24,
  },
  metricCard: {
    background: "#111113", border: "1px solid #1E1E21",
    borderRadius: 12, padding: "18px 20px",
  },
  metricLabel: {
    margin: "0 0 8px", fontSize: 11, color: "#48484A",
    textTransform: "uppercase", letterSpacing: "0.8px", fontWeight: 500,
  },
  metricVal: {
    margin: "0 0 12px", fontSize: 26, fontWeight: 600,
    letterSpacing: "-0.5px", lineHeight: 1,
  },
  metricUnit: { fontSize: 13, fontWeight: 400, opacity: 0.6 },
  metricBar: {
    height: 3, borderRadius: 99, overflow: "hidden",
  },
  metricBarFill: {
    height: "100%", borderRadius: 99, transition: "width 0.6s ease",
  },
  txTypeRow: {
    display: "flex", gap: 10, marginTop: 6,
  },
  filterRow: {
