  },
  pill: {
    display: "flex", alignItems: "center", gap: 6,
    padding: "5px 12px", background: "#111113",
    border: "1px solid #1E1E21", borderRadius: 99,
    color: "#636366", fontSize: 12, fontWeight: 500,
    cursor: "pointer", fontFamily: "inherit", transition: "all 0.15s",
  },
  pillCount: {
    padding: "1px 6px", borderRadius: 99, fontSize: 11,
    background: "#1E1E21", color: "#48484A", fontWeight: 600,
    transition: "all 0.15s",
  },
  listCard: {
    background: "#0D0D0F", border: "1px solid #1A1A1D",
    borderRadius: 14, overflow: "hidden",
  },
  listHeader: {
    display: "flex", padding: "10px 20px",
    borderBottom: "1px solid #1A1A1D",
    fontSize: 10, color: "#3A3A3D", fontWeight: 600,
    letterSpacing: "0.8px", textTransform: "uppercase",
  },
  listRow: {
    display: "flex", alignItems: "center",
    padding: "14px 20px",
    borderBottom: "1px solid #111113",
    background: "transparent", transition: "background 0.1s",
    animation: "fadeIn 0.3s ease both",
  },
  centerState: {
    padding: "60px 20px", textAlign: "center",
  },
  emptyIcon: {
    fontSize: 36, color: "#2C2C2E", margin: "0 auto",
  },
  spinner: {
    width: 28, height: 28, border: "2px solid #1E1E21",
    borderTop: "2px solid #7C71F2", borderRadius: "50%",
    animation: "spin 0.7s linear infinite", margin: "0 auto",
  },
  iconBox: {
    width: 30, height: 30, borderRadius: 8,
    display: "flex", alignItems: "center",
    justifyContent: "center", fontSize: 13,
    fontWeight: 700, flexShrink: 0,
  },
  campaignTag: {
